"""Generate synthetic GPON inventory data as CSV files.

Usage::

    python generate_synthetic_data.py --config config.yaml --output-dir ./output --seed 42

Produces sites.csv, olts.csv, splitters.csv, onts.csv, connections.csv,
and a manifest.json with file list, row counts, and SHA-256 checksums.
"""

import argparse
import csv
import hashlib
import json
import logging
import math
import os
